## Implementasi Operasi Update (Ubah Data)

Buat file `update.php` untuk mengubah data user.

### `update.php`
php
<?php
// Include config file
require_once "config.php";

// Define variables and initialize with empty values
$name = $email = $phone = "";
$name_err = $email_err = $phone_err = "";

// Processing form data when form is submitted
if(isset($_POST["id"]) && !empty($_POST["id"])){
    // Get hidden input value
    $id = $_POST["id"];

    // Validate name
    if(empty(trim($_POST["name"]))){
        $name_err = "Mohon masukkan nama.";
    } else{
        $name = trim($_POST["name"]);
    }

    // Validate email
    if(empty(trim($_POST["email"]))){
        $email_err = "Mohon masukkan email.";     
    } else{
        $sql = "SELECT id FROM users WHERE email = ? AND id <> ?";

        if($stmt = mysqli_prepare($link, $sql)){
            mysqli_stmt_bind_param($stmt, "si", $param_email, $param_id);
            $param_email = trim($_POST["email"]);
            $param_id = $id;

            if(mysqli_stmt_execute($stmt)){
                mysqli_stmt_store_result($stmt);

                if(mysqli_stmt_num_rows($stmt) == 1){
                    $email_err = "Email ini sudah terdaftar.";
                } else{
                    $email = trim($_POST["email"]);
                }
            } else{
                echo "Terjadi kesalahan. Silakan coba lagi nanti.";
            }
            mysqli_stmt_close($stmt);
        }
    }

    // Validate phone
    if(empty(trim($_POST["phone"]))){
        $phone_err = "Mohon masukkan nomor telepon.";
    } else{
        $phone = trim($_POST["phone"]);
    }

    // Check input errors before inserting in database
    if(empty($name_err) && empty($email_err) && empty($phone_err)){
        // Prepare an update statement
        $sql = "UPDATE users SET name=?, email=?, phone=? WHERE id=?";

        if($stmt = mysqli_prepare($link, $sql)){
            // Bind parameters to the prepared statement
            mysqli_stmt_bind_param($stmt, "sssi", $param_name, $param_email, $param_phone, $param_id);

            // Set parameters
            $param_name = $name;
            $param_email = $email;
            $param_phone = $phone;
            $param_id = $id;

            // Attempt to execute the prepared statement
            if(mysqli_stmt_execute($stmt)){
                // Records updated successfully. Redirect to landing page
                header("location: index.php");
                exit();
            } else{
                echo "Terjadi kesalahan. Silakan coba lagi nanti.";
            }
        }
        mysqli_stmt_close($stmt);
    }

    // Close connection
    mysqli_close($link);
} else{
    // Check existence of id parameter before processing further
    if(isset($_GET["id"]) && !empty(trim($_GET["id"]))){
        // Get URL parameter
        $id =  trim($_GET["id"]);

        // Prepare a select statement
        $sql = "SELECT * FROM users WHERE id = ?";
        if($stmt = mysqli_prepare($link, $sql)){
            // Bind variables to the prepared statement as parameters
            mysqli_stmt_bind_param($stmt, "i", $param_id);

            // Set parameters
            $param_id = $id;

            // Attempt to execute the prepared statement
            if(mysqli_stmt_execute($stmt)){
                $result = mysqli_stmt_get_result($stmt);

                if(mysqli_num_rows($result) == 1){
                    /* Fetch result row as an associative array. Since the result set
                    contains only one row, we don't need to use a while loop */
                    $row = mysqli_fetch_array($result, MYSQLI_ASSOC);

                    // Retrieve individual field value
                    $name = $row["name"];
                    $email = $row["email"];
                    $phone = $row["phone"];
                } else{
                    // URL doesn't contain valid id. Redirect to error page
                    header("location: error.php");
                    exit();
                }

            } else{
                echo "Terjadi kesalahan. Silakan coba lagi nanti.";
            }
        }
        // Close statement
        mysqli_stmt_close($stmt);

        // Close connection
        mysqli_close($link);
    }  else{
        // URL doesn't contain id parameter. Redirect to error page
        header("location: error.php");
        exit();
    }
}
?>

